"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["1187"],{1308(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/en/blog/welcome","source":"@site/i18n/en/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Welcome to Heiman Technology Wiki","description":"Welcome to the Heiman Technology Wiki! This is the official knowledge base, bringing together product documentation, technical solutions, industry news, and company updates.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/en/blog/tags/heiman","description":"Heiman Technology news and updates"}],"readingTime":0.6,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/en/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Welcome to Heiman Technology Wiki","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman Matter Smart Smoke Alarm Officially Launched","permalink":"/heiman-wiki-public/en/blog/mdx-blog-post"}},"content":"Welcome to the Heiman Technology Wiki! This is the official knowledge base, bringing together product documentation, technical solutions, industry news, and company updates.\\n\\n{/* truncate */}\\n\\n## About This Site\\n\\nThe Heiman Technology Wiki is dedicated to providing a one-stop technical resource for partners, developers, and customers:\\n\\n- **Products** \u2014 Smart Fire Safety, Smart Gas Safety, Smart Elderly Care, Smart Sensors\\n- **Solutions** \u2014 Industry-level smart security solutions\\n- **Technical Docs** \u2014 API integration guides, SDK usage, installation manuals\\n- **Industry Insights** \u2014 Smart security trends and policy\u89E3\u8BFB\\n\\n## Quick Navigation\\n\\n- Browse [Products & Solutions](/docs/tutorial-basics/create-a-page)\\n- Read [About Us](/docs/intro) to learn Heiman\'s story\\n- Visit the [Heiman Official Site](https://www.heiman.com.cn)\\n\\nFor any questions, call our hotline **400-8959-500** or contact online support."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/en/blog/mdx-blog-post","source":"@site/i18n/en/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman Matter Smart Smoke Alarm Officially Launched","description":"Heiman Technology\'s new generation Matter protocol smart smoke alarm, the HS1SA-M, has been officially launched \u2014 one of the industry\'s first smoke alarms to receive Matter 1.2 certification.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/en/blog/tags/matter","description":"Matter protocol\u76F8\u5173\u5185\u5BB9"},{"inline":false,"label":"Smart Fire Safety","permalink":"/heiman-wiki-public/en/blog/tags/smart-fire","description":"Smart fire safety products and solutions"}],"readingTime":0.66,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/en/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman Matter Smart Smoke Alarm Officially Launched","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Welcome to Heiman Technology Wiki","permalink":"/heiman-wiki-public/en/blog/welcome"},"nextItem":{"title":"Heiman Technology Milestones","permalink":"/heiman-wiki-public/en/blog/long-blog-post"}},"content":"Heiman Technology\'s new generation Matter protocol smart smoke alarm, the HS1SA-M, has been officially launched \u2014 one of the industry\'s first smoke alarms to receive Matter 1.2 certification.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nThe HS1SA-M supports Apple HomeKit, Amazon Alexa, Google Home, and Samsung SmartThings \u2014 the four major smart home ecosystems.\\n\\n:::\\n\\n## Key Features\\n\\n- **Matter 1.2 Certified** \u2014 Cross-brand, cross-ecosystem interoperability\\n- **Photoelectric Smoke Sensing** \u2014 Rapid response to various fire smoke types\\n- **Voice Alarm** \u2014 Multiple language options, clear hazard alerts\\n- **Self-Test Function** \u2014 Regular self-checks to ensure normal operation\\n- **Remote Notification** \u2014 Real-time push alerts to your phone APP\\n\\n## Compatibility\\n\\nThe HS1SA-M seamlessly integrates with major smart home platforms without requiring an additional gateway \u2014 manage everything directly from your phone.\\n\\nVisit the [Products](/docs/tutorial-basics/create-a-page) page to learn more."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/en/blog/long-blog-post","source":"@site/i18n/en/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Heiman Technology Milestones","description":"Since its founding in 2005, Heiman Technology has journeyed over 20 years. This article\u56DE\u987Es Heiman\'s key milestones.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/en/blog/tags/heiman","description":"Heiman Technology news and updates"}],"readingTime":1.05,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/en/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Heiman Technology Milestones","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Matter Smart Smoke Alarm Officially Launched","permalink":"/heiman-wiki-public/en/blog/mdx-blog-post"},"nextItem":{"title":"Heinan Technology Recognized as National \\"Little Giant\\" Enterprise","permalink":"/heiman-wiki-public/en/blog/first-blog-post"}},"content":"Since its founding in 2005, Heiman Technology has journeyed over 20 years. This article\u56DE\u987Es Heiman\'s key milestones.\\n\\n{/* truncate */}\\n\\n## 2005 - Company Founded\\n\\nShenzhen Heiman Technology Co., Ltd. was officially established, entering the security sensor field.\\n\\n## 2006 - International Start\\n\\nMultiple products passed EU CE certification and partnered with China Mobile.\\n\\n## 2011 - International Certification Breakthrough\\n\\nMultiple products passed EU EN54-7 and EN14604 certifications, reaching international quality standards.\\n\\n## 2012 - Smart Home Transformation\\n\\nThe smart home project was fully launched, transitioning Heiman into a company specializing in R&D, production, and sales of smart home products.\\n\\n## 2017 - Major Breakthroughs\\n\\n- Developed China\'s first NB-IoT smoke alarm\\n- Won 2 Red Dot Design Awards\\n- Passed MFi certification, qualified as an Apple manufacturer\\n\\n## 2020 - Capital Boost\\n\\nCompleted Series A financing with Shenzhen\u9AD8\u65B0\u6295 Group, recognized as \\"Guangdong Province Specialized and New SME\\".\\n\\n## 2022 - National Recognition\\n\\nRecognized as National Specialized and New \\"Little Giant\\" Enterprise. K1 series won Red Dot Design Award.\\n\\n## 2023 - International Standards Leadership\\n\\nHeiman testing lab officially passed CNAS certification. Smoke alarms and CO alarms\u9996\u6279\u83B7\u5F97 Matter 1.2 certification.\\n\\n## 2024 - Present\\n\\nContinuing innovation, deepening commitment to Smart Fire Safety, Smart Gas Safety, Smart Elderly Care, and Smart Sensors, providing quality products and services to customers in 100+ countries worldwide."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/en/blog/first-blog-post","source":"@site/i18n/en/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heinan Technology Recognized as National \\"Little Giant\\" Enterprise","description":"In 2022, Heiman Technology was officially recognized as a National Specialized and New \\"Little Giant\\" Enterprise for its deep technical accumulation and innovation in the smart sensor field.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/en/blog/tags/heiman","description":"Heiman Technology news and updates"}],"readingTime":0.45,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/en/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heinan Technology Recognized as National \\"Little Giant\\" Enterprise","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Technology Milestones","permalink":"/heiman-wiki-public/en/blog/long-blog-post"}},"content":"In 2022, Heiman Technology was officially recognized as a National Specialized and New \\"Little Giant\\" Enterprise for its deep technical accumulation and innovation in the smart sensor field.\\n\\n{/* truncate */}\\n\\nThis national-level recognition affirms Heiman\'s excellence in specialization, refinement, differentiation, and innovation. Heiman will continue to deepen its efforts in Smart Fire Safety, Smart Gas Safety, Smart Elderly Care, and Smart Sensors, consistently delivering high-quality products and services to customers.\\n\\nHeiman had previously received recognition as a National High-Tech Enterprise and a Guangdong Province Specialized and New SME."}]}}')}}]);